!function(){"use strict";document.addEventListener("click",function(t){var e=t.target.closest(".tix-cal-btn");if(e)return t.preventDefault(),void e.closest(".tix-cal").classList.toggle("tix-cal-open");if(!t.target.closest(".tix-cal-dropdown"))for(var c=document.querySelectorAll(".tix-cal-open"),l=0;l<c.length;l++)c[l].classList.remove("tix-cal-open")})}();